            if (filters.length == 0)
                return false;
            if (!filters[0].matches(element))
                return false;
            for (int i = 1; i < filters.length; i++) {
                if (filters[i].matches(element))
                    return false;
            }
            return true;
        default:
            return false;
        }
    }

